    when_to_use_this_method: { use_this_when: ["You need to find a place or a route on a flat plan", "You are describing where things are using directions"], use_other_when: ["You only need the shape of a single object (use top view)", "You are naming directions without a drawing (use directions)"] },
    edge_cases: [ { case: "North arrow on a map", value: "Usually points up the page", reasoning: "The map's North arrow tells you which way is North so you can read all the other directions.", where_it_appears: "Every printed map and atlas page" }, { case: "Symbols stand for real things", value: "A small picture = a real place", reasoning: "Maps use tiny symbols (a tree for a park, a cross for a hospital) because real places are too big to draw.", where_it_appears: "Reading the key or legend of a map" } ],
    video_script_hooks: { opening_hook: "Pretend you're a bird looking down at your whole neighbourhood. Draw what you see and you've made a map!", concept_reveal: "A map is just a top-view picture of a place, made small. With a North arrow and a few symbols, you can find your way anywhere." },
